  const[shN,sShN]=useState(false);
  const[noteInput,sNoteInput]=useState("");
  const[noteSection,sNoteSection]=useState(null);
  const cr=useRef(null);
  const T=dk?D:L;
  const ch=CH.find(c=>c.id===aCh);
